import numpy as np

def two_tower_score(
    user_feat: np.ndarray,
    item_feat: np.ndarray,
    user_layers: list[tuple[np.ndarray, np.ndarray]],
    item_layers: list[tuple[np.ndarray, np.ndarray]]
) -> float:
    def tower(x, layers):
        for idx, (W, b) in enumerate(layers):
            x = x @ W.T + b
            if idx < len(layers) - 1:
                x = np.maximum(0, x)  # ReLU for hidden layers
        norm = np.linalg.norm(x)
        return x / norm if norm > 0 else x

    u_repr = tower(user_feat, user_layers)
    i_repr = tower(item_feat, item_layers)
    return float(np.dot(u_repr, i_repr))
